-- 1. Atomic credit reservation RPC (prevents race condition in /api/generate)
CREATE OR REPLACE FUNCTION reserve_credits(org_id UUID, amount NUMERIC)
RETURNS BOOLEAN
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  rows_affected INTEGER;
BEGIN
  UPDATE organizations
  SET credit_balance = credit_balance - amount,
      updated_at = NOW()
  WHERE id = org_id AND credit_balance >= amount;

  GET DIAGNOSTICS rows_affected = ROW_COUNT;
  RETURN rows_affected > 0;
END;
$$;

-- 2. Atomic increment for balance (prevents read-modify-write races)
CREATE OR REPLACE FUNCTION increment_org_balance(org_id UUID, amount NUMERIC)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  UPDATE organizations
  SET credit_balance = credit_balance + amount,
      updated_at = NOW()
  WHERE id = org_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Organization % not found', org_id;
  END IF;
END;
$$;

-- 3. Atomic decrement for balance (used by existing code)
CREATE OR REPLACE FUNCTION decrement_org_balance(org_id UUID, amount NUMERIC)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  UPDATE organizations
  SET credit_balance = credit_balance - amount,
      updated_at = NOW()
  WHERE id = org_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Organization % not found', org_id;
  END IF;
END;
$$;

-- 4. Atomic transaction recording (ledger + balance in one TX)
CREATE OR REPLACE FUNCTION record_transaction_atomic(
  p_org_id UUID,
  p_project_id UUID,
  p_from_agent TEXT,
  p_to_agent TEXT,
  p_amount NUMERIC,
  p_transaction_type TEXT,
  p_description TEXT,
  p_balance_delta NUMERIC
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  -- Insert ledger entry
  INSERT INTO agent_ledger (org_id, project_id, from_agent, to_agent, amount, transaction_type, description)
  VALUES (p_org_id, p_project_id, p_from_agent, p_to_agent, p_amount, p_transaction_type, p_description);

  -- Update balance atomically
  UPDATE organizations
  SET credit_balance = credit_balance + p_balance_delta,
      updated_at = NOW()
  WHERE id = p_org_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Organization % not found', p_org_id;
  END IF;
END;
$$;

-- 5. Fix RLS on projects table
DROP POLICY IF EXISTS "Allow all" ON projects;

-- Proper per-org policies
CREATE POLICY IF NOT EXISTS "Users can view own org projects" ON projects
  FOR SELECT USING (
    org_id IN (SELECT om.org_id FROM org_members om WHERE om.user_id = auth.uid())
  );

CREATE POLICY IF NOT EXISTS "Users can insert own org projects" ON projects
  FOR INSERT WITH CHECK (
    org_id IN (SELECT om.org_id FROM org_members om WHERE om.user_id = auth.uid())
  );

CREATE POLICY IF NOT EXISTS "Users can update own org projects" ON projects
  FOR UPDATE USING (
    org_id IN (SELECT om.org_id FROM org_members om WHERE om.user_id = auth.uid())
  );

CREATE POLICY IF NOT EXISTS "Users can delete own org projects" ON projects
  FOR DELETE USING (
    org_id IN (SELECT om.org_id FROM org_members om WHERE om.user_id = auth.uid())
  );

-- 6. Add unique constraint to prevent double monthly grants
ALTER TABLE credit_transactions
  ADD CONSTRAINT unique_monthly_grant
  UNIQUE (org_id, type, date_trunc('month', created_at))
  WHERE type = 'subscription_grant';
